// Script Continued Below
// KT - REQUEST TYPE
function onSubmit() {
	var formAction = g_form.getActionName();

	// STRY0088787 added if statement to check the submit is a Request submit, then doin save before continuing
	if((formAction == 'openModalRespondClarificationSP')
		|| (formAction == 'openModalRequestClarificationSP')
		|| (formAction == 'openModalRespondExtensionSP')
		|| (formAction == 'openModalRequestExtensionSP')
		|| (formAction == 'openModalRespondReassignmentSP')
		|| (formAction == 'openModalRequestReassignmentSP')
		){
		var task_id = g_form.getUniqueValue();

		var saveMsg = getMessage('Tasker - Modal Save Changes Message');


		var _spModal;
		if(typeof spModal != 'undefined'){
			_spModal = spModal;
		}
		var _spUtil;
		if(typeof spUtil != 'undefined'){
			_spUtil = spUtil;
		}

		if(x_153465_discovert.DTech_Task_Actions==undefined){
			ScriptLoader.getScripts(['x_153465_discovert.DTech_Task_Actions.jsdbx'], function() {
				_requestParameters(task_id, formAction, openRequestModal);
			});
		} else {
			_requestParameters(task_id, formAction, openRequestModal);
		}
		return false;		
	}

	// STRY0103010, STRY0102985, STRY0101757, STRY0104533
	// this is called from the Open Modal callback to refresh the form
	function refreshForm() {
		g_form.save();
	}	

	// STRY0103010, STRY0102985, STRY0101757, STRY0104533
	// Open the modal, will be called after the call back to get the ID or directly from the form action switch
	function openRequestModal(response){
		var params = {};
		var sParams = response.responseXML.documentElement.getAttribute("answer");
		params = JSON.parse(sParams);
		var userCancelled = false;
		userCancelled = x_153465_discovert.DTech_Task_Actions.checkChangesAndConfirmChange(_spModal, g_form, saveMsg);
		// stop only if the user cancelled
		if(userCancelled){
			return false;
		}

		switch(formAction){
			case 'openModalRequestClarificationSP':
				x_153465_discovert.DTech_Task_Actions.requestClarification(_spModal, _spUtil, g_form, params, refreshForm);
				break;
			case 'openModalRespondClarificationSP':
				x_153465_discovert.DTech_Task_Actions.respondToClarificationRequest(_spModal, _spUtil, g_form, params, refreshForm);
				break;
			case 'openModalRequestExtensionSP':
				x_153465_discovert.DTech_Task_Actions.requestExtension(_spModal, _spUtil, g_form, params, refreshForm);
				break;
			case 'openModalRespondExtensionSP':
				x_153465_discovert.DTech_Task_Actions.respondToExtensionRequest(_spModal, _spUtil, g_form, params, refreshForm);
				break;
			case 'openModalRequestReassignmentSP':
				x_153465_discovert.DTech_Task_Actions.requestReassignment(_spModal, _spUtil, g_form, params, refreshForm);
				break;
			case 'openModalRespondReassignmentSP':
				x_153465_discovert.DTech_Task_Actions.respondToReassignmentRequest(_spModal, _spUtil, g_form, params, refreshForm);				
				break;
		}
	}

	//NOTE: this may move out into another file to handle all rest calls from UI Script
	function _requestParameters(task_id, action_name, callback){
		var ajax  = new GlideAjax('ClientTaskInfo');
		ajax.addParam('sysparm_name', 'getTaskUIActionParamaters');
		ajax.addParam('sysparm_task_id', task_id);
		ajax.addParam('sysparm_action_name', action_name);
		ajax.getXML(callback);
	}


}
